def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # Generate candidate b values starting from 0, expanding by adding a elements
    candidates = {0}
    for _ in range(n):
        new_cands = set()
        for c in candidates:
            for x in a:
                new_cands.add(c + x)
                new_cands.add(c - x)
        candidates |= new_cands

    candidates = list(candidates)
    # Limit candidates to avoid TLE
    if len(candidates) > 200:
        candidates = candidates[:200]

    a_multiset = sorted(a)

    for b_combo in combinations_with_replacement(candidates, n):
        b = list(b_combo)
        diffs = set()
        for i in range(len(b)):
            for j in range(len(b)):
                diffs.add(b[i] - b[j])
        if all(x in diffs for x in a):
            print("YES")
            return

    print("NO")

t = int(input())
